module freq_div(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);
  // Frequency division parameters
  parameter DIV_50 = 2;
  parameter DIV_10 = 10;
  parameter DIV_1 = 100;
  // Counter variables
  reg [1:0] cnt_50 = 0;
  reg [3:0] cnt_10 = 0;
  reg [6:0] cnt_1 = 0;
  // CLK_50 generation
  always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
      CLK_50 <= 0;
    end else begin
      CLK_50 <= ~CLK_50;
    end
  end
  // CLK_10 generation
  always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
      CLK_10 <= 0;
      cnt_10 <= 0;
    end else begin
      if (cnt_10 == DIV_10 - 1) begin
        CLK_10 <= ~CLK_10;
        cnt_10 <= 0;
      end else begin
        cnt_10 <= cnt_10 + 1;
      end
    end
  end
  // CLK_1 generation
  always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
      CLK_1 <= 0;
      cnt_1 <= 0;
    end else begin
      if (cnt_1 == DIV_1 - 1) begin
        CLK_1 <= ~CLK_1;
        cnt_1 <= 0;
      end else begin
        cnt_1 <= cnt_1 + 1;
      end
    end
  end
endmodule
